// Pseudocode for tagging and tracking provenance
for (record in dataset) {
  record.metadata = {
    source: getSource(record),
    modality: detectModality(record),
    compliance: checkCompliance(record)
  }
  save(record)
}

// Example: Human-in-the-loop review trigger
if (data.isSensitive() || data.isNewSource()) {
  assignToExpertReviewer(data)
} else {
  autoApprove(data)
}
